const grantKey = $env.JOBTREAD_GRANT_KEY;

if (!grantKey) {
  throw new Error('Missing JOBTREAD_GRANT_KEY');
}

const query = {
  '$': {
    grantKey,
  },
  accounts: {
    '$': {
      filter: {
        type: { eq: 'customer' },
      },
      first: 200,
    },
    nodes: {
      id: {},
      name: {},
      primaryLocationId: {},
      locations: {
        nodes: {
          id: {},
          address: {
            street1: {},
            city: {},
            state: {},
            zip: {},
          },
        },
      },
    },
  },
};

return [{ json: { query } }];

const response = $input.first().json;

if (response.errors?.length) {
  throw new Error(`JT API error: ${response.errors[0].message}`);
}

const nodes = response.accounts?.nodes ?? [];

const customers = nodes.map(node => {
  const locations = node.locations?.nodes ?? [];
  const primaryLocation =
    locations.find(l => l.id === node.primaryLocationId) ?? locations[0] ?? null;

  const address = primaryLocation?.address;

  return {
    id: node.id,
    name: node.name,
    primaryLocationId: node.primaryLocationId,
    address: address
      ? `${address.street1 ?? ''}, ${address.city ?? ''}, ${address.state ?? ''} ${address.zip ?? ''}`.replace(/^,\s*|,\s*,/g, '')
      : null,
    locations: locations.map(l => ({
      id: l.id,
      address: l.address
        ? `${l.address.street1 ?? ''}, ${l.address.city ?? ''}, ${l.address.state ?? ''} ${l.address.zip ?? ''}`.trim()
        : null
    }))
  };
}).sort((a, b) => a.name.localeCompare(b.name));

return [{ json: { customers, count: customers.length } }];
